export const meta = {
  name: 'qa-csrf',
  description: 'QA workflow: CSRF protection in Nablarch web application',
  phases: [
    { title: 'Semantic Search' },
    { title: 'Read Sections' },
    { title: 'Generate Answer' },
  ],
}

phase('Semantic Search')
const searchResult = await agent(
  `Execute the semantic search workflow described in workflows/semantic-search.md for the following query:

Query: "外部サイトから不正にPOSTされるのを防ぎたい。NablarchにCSRF対策の仕組みはある？どう設定する？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）"

The workflow is at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/workflows/semantic-search.md
The knowledge base is at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/

Steps to execute:
1. Read the semantic-search.md workflow file to understand the process
2. Search the knowledge directory for files related to CSRF, セキュリティ, トークン, web security
3. For each candidate page, read its metadata/headers to determine relevance
4. Select the most relevant sections and return them

Return a JSON object with:
{
  "selected_sections": [
    {"file": "<full path to json file>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ],
  "selected_pages": [
    {"path": "<path relative to knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<path relative to knowledge/>", "reason": "<why excluded>"}
  ],
  "excluded_sections": [
    {"file": "<full path>", "section_id": "<sN>", "reason": "<why excluded>"}
  ]
}`,
  { label: 'semantic-search', phase: 'Semantic Search', schema: {
    type: 'object',
    properties: {
      selected_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            file: { type: 'string' },
            section_id: { type: 'string' },
            relevance: { type: 'string', enum: ['high', 'partial'] },
            reason: { type: 'string' }
          },
          required: ['file', 'section_id', 'relevance', 'reason']
        }
      },
      selected_pages: {
        type: 'array',
        items: {
          type: 'object',
          properties: { path: { type: 'string' }, reason: { type: 'string' } },
          required: ['path', 'reason']
        }
      },
      excluded_pages: {
        type: 'array',
        items: {
          type: 'object',
          properties: { path: { type: 'string' }, reason: { type: 'string' } },
          required: ['path', 'reason']
        }
      },
      excluded_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: { file: { type: 'string' }, section_id: { type: 'string' }, reason: { type: 'string' } },
          required: ['file', 'section_id', 'reason']
        }
      }
    },
    required: ['selected_sections', 'selected_pages', 'excluded_pages', 'excluded_sections']
  }}
)

log(`Semantic search complete. Selected ${searchResult.selected_sections.length} sections.`)

phase('Read Sections')

// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

log(`Reading ${sectionsToRead.length} sections (${highSections.length} high, ${Math.min(partialSections.length, 10 - highSections.length)} partial)`)

const readArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`).join(' ')

const sectionsContent = await agent(
  `Run the following bash command and return the complete output verbatim:

bash /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh ${readArgs}

Return the complete raw output as a string.`,
  { label: 'read-sections', phase: 'Read Sections' }
)

phase('Generate Answer')

const answer = await agent(
  `You are a Nablarch expert answering questions in Japanese.

## Question
外部サイトから不正にPOSTされるのを防ぎたい。NablarchにCSRF対策の仕組みはある？どう設定する？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）

## Section Content
${sectionsContent}

## Instructions
Generate a Japanese answer following this format:

**結論**: Direct answer (1-2 sentences with specific method/class names)

**根拠**: Code examples, configuration examples backing the conclusion
- Show code/config in code blocks
- Quote code verbatim from sections

**注意点**: Constraints, common mistakes (omit if nothing applies)

参照: Only sections actually cited (file.json:sN format, omit category path)

Stay within 500 tokens (up to 800 for complex questions).

Then verify: check all Nablarch-specific claims (API names, class names, config methods, behavior specs, constraints, parameters) are supported by the section content.

Return JSON with:
{
  "answer_text": "<the full Japanese answer>",
  "verify_result": "PASS" or "FAIL",
  "issues": ["<unsupported claim 1>", ...],
  "used_sections": [{"ref": "<file.json:sN>", "reason": "<why used>"}],
  "unused_sections": [{"ref": "<file.json:sN>", "reason": "<why not used>"}]
}`,
  { label: 'generate-answer', phase: 'Generate Answer', schema: {
    type: 'object',
    properties: {
      answer_text: { type: 'string' },
      verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
      issues: { type: 'array', items: { type: 'string' } },
      used_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: { ref: { type: 'string' }, reason: { type: 'string' } },
          required: ['ref', 'reason']
        }
      },
      unused_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: { ref: { type: 'string' }, reason: { type: 'string' } },
          required: ['ref', 'reason']
        }
      }
    },
    required: ['answer_text', 'verify_result', 'issues', 'used_sections', 'unused_sections']
  }}
)

let finalAnswer = answer.answer_text

if (answer.verify_result === 'FAIL') {
  log(`Verify FAIL. Issues: ${answer.issues.join(', ')}. Re-generating answer...`)
  const revised = await agent(
    `You are a Nablarch expert answering questions in Japanese.

## Question
外部サイトから不正にPOSTされるのを防ぎたい。NablarchにCSRF対策の仕組みはある？どう設定する？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）

## Section Content
${sectionsContent}

## IMPORTANT: Do NOT include these unsupported claims in your answer:
${answer.issues.map(i => `- ${i}`).join('\n')}

## Instructions
Generate a Japanese answer following this format:

**結論**: Direct answer (1-2 sentences with specific method/class names)

**根拠**: Code examples, configuration examples backing the conclusion
- Show code/config in code blocks  
- Quote code verbatim from sections

**注意点**: Constraints, common mistakes (omit if nothing applies)

参照: Only sections actually cited (file.json:sN format, omit category path)

Stay within 500 tokens. Only include claims directly supported by the section content.`,
    { label: 'regenerate-answer', phase: 'Generate Answer' }
  )
  finalAnswer = revised
}

return {
  final_answer: finalAnswer,
  verify_result: answer.verify_result,
  search_result: searchResult,
  sections_to_read: sectionsToRead,
  used_sections: answer.used_sections,
  unused_sections: answer.unused_sections
}

